export interface ApiClientOptions {
  apiUrl: string;
  token?: string | undefined;
  fetchImpl?: typeof fetch | undefined;
}

export interface ApiErrorBody {
  error?: {
    code?: unknown;
    message?: unknown;
    requestId?: unknown;
  };
}

export class ApiClientError extends Error {
  readonly code: string;
  readonly status: number;
  readonly requestId: string | undefined;

  constructor(status: number, code: string, message: string, requestId?: string) {
    super(message);
    this.name = "ApiClientError";
    this.status = status;
    this.code = code;
    this.requestId = requestId;
  }

  toJSON(): { error: { code: string; message: string; status: number; requestId?: string } } {
    return {
      error: {
        code: this.code,
        message: this.message,
        status: this.status,
        ...(this.requestId ? { requestId: this.requestId } : {})
      }
    };
  }
}

export class ApiClient {
  private readonly apiUrl: string;
  private readonly token: string | undefined;
  private readonly fetchImpl: typeof fetch;

  constructor(options: ApiClientOptions) {
    this.apiUrl = options.apiUrl.replace(/\/+$/u, "");
    this.token = options.token;
    this.fetchImpl = options.fetchImpl ?? fetch;
  }

  async login(email: string, password: string): Promise<unknown> {
    return this.request("/api/login", {
      method: "POST",
      body: { email, password },
      auth: false
    });
  }

  async session(): Promise<unknown> {
    return this.request("/api/session", { method: "GET" });
  }

  async projects(): Promise<unknown> {
    return this.request("/api/projects", { method: "GET" });
  }

  async selectProject(projectId: string): Promise<unknown> {
    return this.request(`/api/projects/${encodeURIComponent(projectId)}/select`, { method: "POST" });
  }

  async registry(): Promise<unknown> {
    return this.request("/api/registry", { method: "GET" });
  }

  async management(projectId: string): Promise<unknown> {
    return this.request(`/api/projects/${encodeURIComponent(projectId)}/management`, { method: "GET" });
  }

  async listChat(projectId: string): Promise<unknown> {
    return this.request(`/api/projects/${encodeURIComponent(projectId)}/chat`, { method: "GET" });
  }

  async sendChat(projectId: string, message: string): Promise<unknown> {
    return this.request(`/api/projects/${encodeURIComponent(projectId)}/chat`, {
      method: "POST",
      body: { message }
    });
  }

  private async request(
    path: string,
    options: { method: "GET" | "POST"; body?: unknown; auth?: boolean }
  ): Promise<unknown> {
    const headers: Record<string, string> = { accept: "application/json" };
    if (options.body !== undefined) {
      headers["content-type"] = "application/json";
    }
    if (options.auth !== false && this.token) {
      headers.authorization = `Bearer ${this.token}`;
    }

    const requestInit: RequestInit = {
      method: options.method,
      headers
    };
    if (options.body !== undefined) {
      requestInit.body = JSON.stringify(options.body);
    }

    const response = await this.fetchImpl(`${this.apiUrl}${path}`, requestInit);

    const payload = await readJson(response);
    if (!response.ok) {
      throw errorFromResponse(response.status, payload);
    }
    return payload;
  }
}

async function readJson(response: Response): Promise<unknown> {
  const text = await response.text();
  if (!text) {
    return null;
  }

  try {
    return JSON.parse(text) as unknown;
  } catch {
    if (!response.ok) {
      throw new ApiClientError(response.status, "api_invalid_json", "API returned a non-JSON error response.");
    }
    throw new ApiClientError(response.status, "api_invalid_json", "API returned a non-JSON response.");
  }
}

function errorFromResponse(status: number, payload: unknown): ApiClientError {
  const body = payload as ApiErrorBody;
  const code = typeof body?.error?.code === "string" ? body.error.code : "api_error";
  const message = typeof body?.error?.message === "string" ? body.error.message : "API request failed.";
  const requestId = typeof body?.error?.requestId === "string" ? body.error.requestId : undefined;
  return new ApiClientError(status, code, message, requestId);
}

import { ApiClient, ApiClientError } from "./api.js";
import {
  type CliConfig,
  type ConfigStoreOptions,
  getConfigDiagnostics,
  loadConfig,
  redactConfig,
  saveConfig
} from "./config.js";

const DEFAULT_API_URL = "http://127.0.0.1:3000";

export interface CommandIO {
  stdout: Pick<NodeJS.WriteStream, "write">;
  stderr: Pick<NodeJS.WriteStream, "write">;
}

export interface CommandOptions extends ConfigStoreOptions {
  fetchImpl?: typeof fetch;
  io?: CommandIO;
}

export interface CommandResult {
  exitCode: number;
}

export class CliCommandError extends Error {
  readonly code: string;
  readonly requestId: string | undefined;
  readonly status: number | undefined;

  constructor(code: string, message: string, options: { requestId?: string; status?: number } = {}) {
    super(message);
    this.name = "CliCommandError";
    this.code = code;
    this.requestId = options.requestId;
    this.status = options.status;
  }

  toJSON(): { error: { code: string; message: string; requestId?: string; status?: number } } {
    return {
      error: {
        code: this.code,
        message: this.message,
        ...(this.requestId ? { requestId: this.requestId } : {}),
        ...(this.status ? { status: this.status } : {})
      }
    };
  }
}

export async function runCommand(argv: string[], options: CommandOptions = {}): Promise<CommandResult> {
  const io = options.io ?? { stdout: process.stdout, stderr: process.stderr };
  const [command, ...args] = argv;

  if (!command || command === "help" || command === "--help") {
    io.stdout.write("building-agent <login|session|projects|use|registry|management|chat|chat:list|config-path>\n");
    return { exitCode: 0 };
  }

  try {
    const output = await execute(command, args, options);
    if (output !== undefined) {
      printJson(io.stdout, output);
    }
    return { exitCode: 0 };
  } catch (error) {
    if (error instanceof Error && error.name === "CliConfigError") {
      throw error;
    }
    await recordFailure(command, error, options);
    printJson(io.stderr, serializeError(error));
    return { exitCode: 1 };
  }
}

async function execute(command: string, args: string[], options: CommandOptions): Promise<unknown> {
  if (command === "config-path") {
    return getConfigDiagnostics(options);
  }

  if (command === "login") {
    const flags = parseFlags(args);
    const email = valueFromFlag(flags, "email");
    const password = valueFromFlag(flags, "password");
    const apiUrl = valueFromFlag(flags, "api-url") ?? DEFAULT_API_URL;
    if (!email || !password) {
      throw new CliCommandError("cli_usage", "login requires --email and --password.");
    }

    const api = new ApiClient({ apiUrl, fetchImpl: options.fetchImpl });
    const response = await api.login(email, password);
    const token = tokenFromLogin(response);
    await saveConfig({ ...(await loadConfig(options)), apiUrl, token, lastCommand: command }, options);
    return { ...withoutToken(response), apiUrl, config: redactConfig(await loadConfig(options)) };
  }

  if (command === "session") {
    const config = await loadConfig(options);
    if (!hasApiAuth(config)) {
      return { diagnostics: getConfigDiagnostics(options), config: redactConfig(config) };
    }
    const response = await clientFromConfig(config, options).session();
    await saveConfig({ ...config, lastCommand: command }, options);
    return { ...asRecord(response), config: redactConfig(await loadConfig(options)) };
  }

  if (command === "projects") {
    const config = await requireApiAuth(command, options);
    const response = await clientFromConfig(config, options).projects();
    await saveConfig({ ...config, lastCommand: command }, options);
    return response;
  }

  if (command === "use") {
    const projectId = args[0];
    if (!projectId) {
      throw new CliCommandError("cli_usage", "use requires a project id.");
    }
    const config = await requireApiAuth(command, options);
    const response = await clientFromConfig(config, options).selectProject(projectId);
    await saveConfig({ ...config, selectedProjectId: projectId, lastCommand: command }, options);
    return { ...asRecord(response), config: redactConfig(await loadConfig(options)) };
  }

  if (command === "registry") {
    const config = await requireApiAuth(command, options);
    const response = await clientFromConfig(config, options).registry();
    await saveConfig({ ...config, lastCommand: command }, options);
    return response;
  }

  if (command === "management") {
    const config = await requireSelectedProject(command, options);
    const response = await clientFromConfig(config, options).management(config.selectedProjectId);
    await saveConfig({ ...config, lastCommand: command }, options);
    return response;
  }

  if (command === "chat:list") {
    const config = await requireSelectedProject(command, options);
    const response = await clientFromConfig(config, options).listChat(config.selectedProjectId);
    await saveConfig({ ...config, lastCommand: command }, options);
    return response;
  }

  if (command === "chat") {
    const message = args.join(" ").trim();
    if (!message) {
      throw new CliCommandError("chat_invalid", "Chat message must be 1-1000 characters.");
    }
    const config = await requireSelectedProject(command, options);
    const response = await clientFromConfig(config, options).sendChat(config.selectedProjectId, message);
    await saveConfig({ ...config, lastCommand: command }, options);
    return response;
  }

  throw new CliCommandError("cli_unknown_command", `Unknown command: ${command}`);
}

function parseFlags(args: string[]): Map<string, string> {
  const flags = new Map<string, string>();
  for (let index = 0; index < args.length; index += 1) {
    const arg = args[index];
    if (!arg?.startsWith("--")) {
      continue;
    }
    const [rawKey, inlineValue] = arg.slice(2).split("=", 2);
    const value = inlineValue ?? args[index + 1];
    if (inlineValue === undefined) {
      index += 1;
    }
    if (rawKey && value !== undefined) {
      flags.set(rawKey, value);
    }
  }
  return flags;
}

function valueFromFlag(flags: Map<string, string>, key: string): string | undefined {
  const value = flags.get(key)?.trim();
  return value ? value : undefined;
}

function clientFromConfig(config: CliConfig, options: CommandOptions): ApiClient {
  return new ApiClient({ apiUrl: config.apiUrl ?? DEFAULT_API_URL, token: config.token, fetchImpl: options.fetchImpl });
}

function hasApiAuth(config: CliConfig): config is CliConfig & { apiUrl: string; token: string } {
  return Boolean(config.apiUrl && config.token);
}

async function requireApiAuth(command: string, options: CommandOptions): Promise<CliConfig & { apiUrl: string; token: string }> {
  const config = await loadConfig(options);
  if (!hasApiAuth(config)) {
    throw new CliCommandError("auth_missing", `${command} requires login first.`);
  }
  return config;
}

async function requireSelectedProject(
  command: string,
  options: CommandOptions
): Promise<CliConfig & { apiUrl: string; token: string; selectedProjectId: string }> {
  const config = await requireApiAuth(command, options);
  if (!config.selectedProjectId) {
    throw new CliCommandError("project_not_selected", `${command} requires selecting a project first.`);
  }
  return { ...config, selectedProjectId: config.selectedProjectId };
}

function tokenFromLogin(response: unknown): string {
  const token = (response as { token?: unknown }).token;
  if (typeof token !== "string" || !token) {
    throw new CliCommandError("auth_invalid", "Login response did not include a bearer token.");
  }
  return token;
}

function withoutToken(response: unknown): Record<string, unknown> {
  const record = asRecord(response);
  const { token: _token, ...safe } = record;
  return safe;
}

function asRecord(value: unknown): Record<string, unknown> {
  return value !== null && typeof value === "object" && !Array.isArray(value) ? (value as Record<string, unknown>) : {};
}

async function recordFailure(command: string, error: unknown, options: CommandOptions): Promise<void> {
  try {
    const config = await loadConfig(options);
    const serialized = serializeError(error).error;
    await saveConfig(
      {
        ...config,
        lastCommand: command,
        lastErrorCode: serialized.code,
        ...(serialized.requestId ? { lastRequestId: serialized.requestId } : {})
      },
      options
    );
  } catch {
    // Preserve the original failure. Config errors are already emitted when they are the original error.
  }
}

function serializeError(error: unknown): { error: { code: string; message: string; requestId?: string; status?: number } } {
  if (error instanceof ApiClientError || error instanceof CliCommandError) {
    return error.toJSON();
  }
  return { error: { code: "cli_error", message: error instanceof Error ? error.message : "Unknown CLI error" } };
}

function printJson(stream: Pick<NodeJS.WriteStream, "write">, value: unknown): void {
  stream.write(`${JSON.stringify(value, null, 2)}\n`);
}

#!/usr/bin/env node
import { CliConfigError } from "./config.js";
import { runCommand } from "./commands.js";

try {
  const result = await runCommand(process.argv.slice(2));
  process.exitCode = result.exitCode;
} catch (error) {
  if (error instanceof CliConfigError) {
    process.stderr.write(`${JSON.stringify(error.toJSON())}\n`);
    process.exitCode = 1;
  } else {
    process.stderr.write(`${error instanceof Error ? error.message : "Unknown CLI error"}\n`);
    process.exitCode = 1;
  }
}

import { mkdir, readFile, writeFile } from "node:fs/promises";
import { homedir } from "node:os";
import { dirname, join, resolve } from "node:path";

const CONFIG_DIRECTORY_NAME = ".building-agent";
const CONFIG_FILE_NAME = "config.json";

export interface CliConfig {
  apiUrl?: string;
  token?: string;
  selectedProjectId?: string;
  lastCommand?: string;
  lastErrorCode?: string;
  lastRequestId?: string;
}

export interface ConfigStoreOptions {
  homeDir?: string;
  env?: NodeJS.ProcessEnv;
}

export interface ConfigDiagnostics {
  cliHomeDir: string;
  configPath: string;
}

export class CliConfigError extends Error {
  readonly code: "config_parse_failed" | "config_read_failed" | "config_write_failed";
  readonly diagnostics: ConfigDiagnostics;

  constructor(
    code: CliConfigError["code"],
    message: string,
    diagnostics: ConfigDiagnostics,
    cause?: unknown
  ) {
    super(message, { cause });
    this.name = "CliConfigError";
    this.code = code;
    this.diagnostics = diagnostics;
  }

  toJSON(): { error: { code: string; message: string; cliHomeDir: string; configPath: string } } {
    return {
      error: {
        code: this.code,
        message: this.message,
        cliHomeDir: this.diagnostics.cliHomeDir,
        configPath: this.diagnostics.configPath
      }
    };
  }
}

function configuredHomeDir(options: ConfigStoreOptions = {}): string {
  const env = options.env ?? process.env;
  return options.homeDir ?? env.BUILDING_AGENT_CLI_HOME ?? homedir();
}

export function getConfigDiagnostics(options: ConfigStoreOptions = {}): ConfigDiagnostics {
  const cliHomeDir = resolve(configuredHomeDir(options));
  return {
    cliHomeDir,
    configPath: join(cliHomeDir, CONFIG_DIRECTORY_NAME, CONFIG_FILE_NAME)
  };
}

function assertPlainConfig(value: unknown, diagnostics: ConfigDiagnostics): CliConfig {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    throw new CliConfigError("config_parse_failed", "CLI config file must contain a JSON object.", diagnostics);
  }

  const candidate = value as Record<string, unknown>;
  for (const key of ["apiUrl", "token", "selectedProjectId", "lastCommand", "lastErrorCode", "lastRequestId"] as const) {
    if (candidate[key] !== undefined && typeof candidate[key] !== "string") {
      throw new CliConfigError("config_parse_failed", `CLI config field ${key} must be a string.`, diagnostics);
    }
  }

  return {
    ...(typeof candidate.apiUrl === "string" ? { apiUrl: candidate.apiUrl } : {}),
    ...(typeof candidate.token === "string" ? { token: candidate.token } : {}),
    ...(typeof candidate.selectedProjectId === "string" ? { selectedProjectId: candidate.selectedProjectId } : {}),
    ...(typeof candidate.lastCommand === "string" ? { lastCommand: candidate.lastCommand } : {}),
    ...(typeof candidate.lastErrorCode === "string" ? { lastErrorCode: candidate.lastErrorCode } : {}),
    ...(typeof candidate.lastRequestId === "string" ? { lastRequestId: candidate.lastRequestId } : {})
  };
}

export async function loadConfig(options: ConfigStoreOptions = {}): Promise<CliConfig> {
  const diagnostics = getConfigDiagnostics(options);

  try {
    const raw = await readFile(diagnostics.configPath, "utf8");
    return assertPlainConfig(JSON.parse(raw) as unknown, diagnostics);
  } catch (error) {
    if (error instanceof CliConfigError) {
      throw error;
    }

    if (error instanceof SyntaxError) {
      throw new CliConfigError("config_parse_failed", "CLI config file contains malformed JSON.", diagnostics, error);
    }

    if (typeof error === "object" && error !== null && "code" in error && error.code === "ENOENT") {
      return {};
    }

    throw new CliConfigError("config_read_failed", "Failed to read CLI config file.", diagnostics, error);
  }
}

export async function saveConfig(config: CliConfig, options: ConfigStoreOptions = {}): Promise<ConfigDiagnostics> {
  const diagnostics = getConfigDiagnostics(options);
  const safeConfig = assertPlainConfig(config, diagnostics);

  try {
    await mkdir(dirname(diagnostics.configPath), { recursive: true, mode: 0o700 });
    await writeFile(diagnostics.configPath, `${JSON.stringify(safeConfig, null, 2)}\n`, { mode: 0o600 });
    return diagnostics;
  } catch (error) {
    throw new CliConfigError("config_write_failed", "Failed to write CLI config file.", diagnostics, error);
  }
}

export function redactConfig(config: CliConfig): CliConfig {
  return {
    ...config,
    ...(config.token ? { token: "[redacted]" } : {})
  };
}

import Fastify, { type FastifyInstance, type FastifyReply } from "fastify";
import cors from "@fastify/cors";
import {
  authenticateRequest,
  getPermissionsForSelectedProject,
  requestIdFor,
  requirePermission,
  requireProjectMembership,
  requireSelectedProject,
  sendError
} from "./auth.js";
import { createSeedStore, type ChatMessage, type SeedStore } from "./seed.js";

interface BuildServerOptions {
  store?: SeedStore;
}

interface ProjectParams {
  projectId: string;
}

interface LoginBody {
  email?: unknown;
  password?: unknown;
}

interface ChatBody {
  message?: unknown;
}

let messageSequence = 0;

function nextMessageId(): string {
  messageSequence += 1;
  return `msg_${String(messageSequence).padStart(6, "0")}`;
}

function bounded<T>(items: T[], limit: number): T[] {
  return items.slice(0, limit);
}

function boundedPlaceholderList<T>(items: T[], store: SeedStore): T[] {
  return bounded(items, store.maxListSize);
}

function isReply(value: unknown): value is FastifyReply {
  return typeof value === "object" && value !== null && "sent" in value;
}

function validateChatMessage(body: unknown): string | null {
  if (typeof body !== "object" || body === null || Array.isArray(body)) {
    return null;
  }

  const message = (body as ChatBody).message;
  if (typeof message !== "string") {
    return null;
  }

  const trimmed = message.trim();
  if (trimmed.length === 0 || trimmed.length > 1000) {
    return null;
  }

  return trimmed;
}

export function buildServer(options: BuildServerOptions = {}): FastifyInstance {
  const store = options.store ?? createSeedStore();
  messageSequence = 0;

  const app = Fastify({
    logger: false,
    genReqId: (() => {
      let sequence = 0;
      return () => {
        sequence += 1;
        return `req_${String(sequence).padStart(6, "0")}`;
      };
    })()
  });

  void app.register(cors, { origin: true });

  app.get("/health", async (request) => ({
    ok: true,
    service: "building-agent-api",
    requestId: requestIdFor(request)
  }));

  app.post<{ Body: LoginBody }>("/api/login", async (request, reply) => {
    const { email, password } = request.body ?? {};
    if (typeof email !== "string" || typeof password !== "string" || !email.trim() || !password) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const user = store.users.find((candidate) => candidate.email === email && candidate.password === password);
    if (!user) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const token = Object.entries(store.tokens).find(([, userId]) => userId === user.id)?.[0];
    if (!token) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    store.sessionsByToken[token] = store.sessionsByToken[token] ?? { userId: user.id, selectedProjectId: null };

    return {
      token,
      user: { id: user.id, name: user.name },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/session", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    return {
      session: {
        userId: session.userId,
        projectId: session.projectId,
        permissions: session.permissions
      },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/projects", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const memberships = store.memberships.filter((membership) => membership.userId === session.userId);
    const projects = bounded(memberships, store.maxListSize).flatMap((membership) => {
      const project = store.projects.find((candidate) => candidate.id === membership.projectId);
      return project ? [{ id: project.id, name: project.name, permissions: membership.permissions }] : [];
    });

    return { projects, limit: store.maxListSize, requestId: requestIdFor(request) };
  });

  app.get("/api/registry", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    return {
      runtimeProviders: boundedPlaceholderList(store.runtimeProviders, store),
      tools: boundedPlaceholderList(store.tools, store),
      skills: boundedPlaceholderList(store.skills, store),
      gateways: boundedPlaceholderList(store.gateways, store),
      buildingCapabilities: boundedPlaceholderList(store.buildingCapabilities, store),
      limit: store.maxListSize,
      placeholderOnly: true,
      requestId: requestIdFor(request)
    };
  });

  app.get<{ Params: ProjectParams }>("/api/projects/:projectId/management", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const readable = requirePermission(request, reply, membership, "chat:read");
    if (isReply(readable)) {
      return readable;
    }

    const management = store.managementByProject[request.params.projectId] ?? {
      gateways: [],
      capabilities: [],
      tools: []
    };

    return {
      projectId: request.params.projectId,
      gateways: boundedPlaceholderList(management.gateways, store),
      capabilities: boundedPlaceholderList(management.capabilities, store),
      tools: boundedPlaceholderList(management.tools, store),
      limit: store.maxListSize,
      placeholderOnly: true,
      requestId: requestIdFor(request)
    };
  });

  app.post<{ Params: ProjectParams }>("/api/projects/:projectId/select", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selectedSession = {
      userId: session.userId,
      selectedProjectId: request.params.projectId
    };
    store.sessionsByToken[session.token] = selectedSession;

    return {
      session: {
        userId: session.userId,
        projectId: request.params.projectId,
        permissions: getPermissionsForSelectedProject(store, selectedSession)
      },
      requestId: requestIdFor(request)
    };
  });

  app.get<{ Params: ProjectParams }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const readable = requirePermission(request, reply, membership, "chat:read");
    if (isReply(readable)) {
      return readable;
    }

    return {
      messages: bounded(store.messagesByProject[request.params.projectId] ?? [], store.maxListSize),
      limit: store.maxListSize,
      requestId: requestIdFor(request)
    };
  });

  app.post<{ Params: ProjectParams; Body: ChatBody }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const writable = requirePermission(request, reply, membership, "chat:write");
    if (isReply(writable)) {
      return writable;
    }

    const content = validateChatMessage(request.body);
    if (!content) {
      return sendError(request, reply, 422, "chat_invalid", "Chat message must be 1-1000 characters.");
    }

    const messages = store.messagesByProject[request.params.projectId] ?? [];
    const message: ChatMessage = {
      id: nextMessageId(),
      projectId: request.params.projectId,
      userId: session.userId,
      role: "user",
      content
    };
    messages.push(message);
    if (messages.length > store.maxChatMessages) {
      messages.splice(0, messages.length - store.maxChatMessages);
    }
    store.messagesByProject[request.params.projectId] = messages;

    return reply.status(201).send({ message, requestId: requestIdFor(request) });
  });

  app.setErrorHandler((error, request, reply) => {
    if (error.validation) {
      return sendError(request, reply, 422, "chat_invalid", "Request payload is invalid.");
    }

    request.log.error({ err: error, requestId: requestIdFor(request) }, "Unhandled API error");
    return sendError(request, reply, 500, "internal_error", "Unexpected API error.");
  });

  return app;
}

